    });
    expect(record.modelId).toBe("ambient-codex");

    const index = readRunIndex(RUN_ID, { fs, rootDir: "runs" }) as RunGenerationIndex;
    const floor = index.floors.find((entry) => entry.depth === 7);
    expect(floor?.outcome).toEqual({
